import { motion } from "framer-motion";
import { useNavigate } from "react-router-dom";
import { useState } from "react";
import {
  BookOpen,
  BarChart3,
  Users,
  Clock,
  Sun,
  Moon,
} from "lucide-react";

export default function Home() {
  const navigate = useNavigate();

  const [darkMode, setDarkMode] = useState(false); // changed here only

  const accent = darkMode ? "text-cyan-400" : "text-blue-700";
  const accentBg = darkMode ? "bg-cyan-500" : "bg-blue-700";
  const accentBorder = darkMode ? "border-cyan-500" : "border-blue-700";

  const features = [
    {
      icon: <BookOpen />,
      title: "Smart Notes Sharing",
      desc: "Faculty upload structured notes while students access organized learning material instantly.",
    },
    {
      icon: <Clock />,
      title: "Syllabus Tracking",
      desc: "Track syllabus completion and stay updated with pending academic units.",
    },
    {
      icon: <BarChart3 />,
      title: "Advanced Analytics",
      desc: "Powerful analytics show how students interact with academic content.",
    },
    {
      icon: <Users />,
      title: "Role Based Dashboards",
      desc: "Separate dashboards for Students, Faculty and Admin with dedicated features.",
    },
  ];

  return (
    <div
      className={`min-h-screen transition-all duration-500 ${
        darkMode
          ? "bg-[#020617] text-white"
          : "bg-white text-gray-900"
      }`}
    >

      {/* NAVBAR */}
      <nav
        className={`flex justify-between items-center px-8 py-5 border-b ${
          darkMode ? "border-gray-800" : "border-gray-200"
        }`}
      >
        <h1 className="text-2xl font-bold">
          Campus<span className={accent}>Notes</span>
        </h1>

        <div className="flex items-center gap-6">
          <button
            onClick={() => navigate("/login")}
            className="hover:opacity-80 transition"
          >
            Login
          </button>

          <button
            onClick={() => navigate("/register")}
            className={`${accentBg} text-white px-5 py-2 rounded-lg font-semibold hover:scale-105 transition`}
          >
            Get Started
          </button>

          <button
            onClick={() => setDarkMode(!darkMode)}
            className={`p-2 rounded-lg border ${
              darkMode ? "border-gray-700" : "border-gray-300"
            }`}
          >
            {darkMode ? <Sun size={18} /> : <Moon size={18} />}
          </button>
        </div>
      </nav>

      {/* HERO */}
      <section
        className={`min-h-[80vh] flex items-center justify-center px-6 relative overflow-hidden
        ${
          darkMode
            ? "bg-[#020617]"
            : "bg-gradient-to-br from-blue-100 via-white to-blue-200"
        }`}
      >

        {darkMode && (
          <div className="absolute w-[600px] h-[600px] bg-cyan-500/20 blur-[120px] rounded-full top-20 left-1/2 -translate-x-1/2" />
        )}

        <div className="max-w-5xl text-center relative z-10">

          <motion.h1
            initial={{ opacity: 0, y: 60 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
            className="text-5xl md:text-7xl font-bold mb-6"
          >
            Campus<span className={accent}>Notes</span>
          </motion.h1>

          <p
            className={`text-lg md:text-xl ${
              darkMode ? "text-gray-300" : "text-gray-600"
            }`}
          >
            Smart Academic Notes Sharing Platform
          </p>

          <p
            className={`mt-4 max-w-2xl mx-auto ${
              darkMode ? "text-gray-400" : "text-gray-500"
            }`}
          >
            A centralized platform where students and faculty share organized
            academic notes with analytics and exam preparation tools.
          </p>

          <div className="mt-10 flex justify-center gap-6">

            <button
              onClick={() => navigate("/register")}
              className={`${accentBg} text-white px-8 py-4 rounded-xl font-semibold hover:scale-105 transition`}
            >
              Get Started
            </button>

            <button
              onClick={() => navigate("/login")}
              className={`border px-8 py-4 rounded-xl transition ${
                darkMode
                  ? "hover:bg-white hover:text-black"
                  : "hover:bg-blue-700 hover:text-white"
              }`}
            >
              Login
            </button>

          </div>

        </div>
      </section>

      {/* SECTION DIVIDER */}
      <div
        className={`h-px w-full bg-gradient-to-r from-transparent ${
          darkMode ? "via-cyan-500" : "via-blue-700"
        } to-transparent opacity-40`}
      />

      {/* FEATURES */}
      <section className="py-24 px-6">

        <div className="max-w-6xl mx-auto">

          <h2 className="text-4xl font-bold text-center mb-16">
            Powerful Platform Features
          </h2>

          <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-10">

            {features.map((feature, index) => (
              <motion.div
                key={index}
                whileHover={{ y: -10 }}
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                className={`p-8 rounded-2xl border relative transition ${
                  darkMode
                    ? "bg-[#0f172a] border-gray-800 hover:border-cyan-500"
                    : "bg-gray-100 border-gray-200 hover:border-blue-700"
                }`}
              >
                <div className={`${accent} mb-4`}>
                  {feature.icon}
                </div>

                <h3 className="text-xl font-semibold mb-2">
                  {feature.title}
                </h3>

                <p
                  className={`text-sm ${
                    darkMode
                      ? "text-gray-400"
                      : "text-gray-500"
                  }`}
                >
                  {feature.desc}
                </p>

              </motion.div>
            ))}

          </div>
        </div>
      </section>

      {/* DIVIDER */}
      <div
        className={`h-px w-full bg-gradient-to-r from-transparent ${
          darkMode ? "via-cyan-500" : "via-blue-700"
        } to-transparent opacity-40`}
      />

      {/* HOW IT WORKS */}
      <section className="py-24 px-6">

        <div className="max-w-5xl mx-auto text-center">

          <h2 className="text-4xl font-bold mb-16">
            How It Works
          </h2>

          <div className="grid md:grid-cols-3 gap-10">

            <Step number="1" title="Faculty Upload Notes" darkMode={darkMode} />

            <Step number="2" title="Students Access Material" darkMode={darkMode} />

            <Step number="3" title="Track Analytics & Exam Prep" darkMode={darkMode} />

          </div>

        </div>
      </section>

      {/* CTA */}
      <section
        className={`py-24 text-center px-6 ${
          darkMode ? "bg-[#0f172a]" : "bg-blue-700 text-white"
        }`}
      >

        <h2 className="text-4xl font-bold mb-6">
          Start Sharing Knowledge Today
        </h2>

        <button
          onClick={() => navigate("/register")}
          className={`${accentBg} text-white px-10 py-4 rounded-xl hover:scale-105 transition`}
        >
          Get Started
        </button>

      </section>

      {/* FOOTER */}
      <footer
        className={`py-10 text-center border-t ${
          darkMode ? "border-gray-800" : "border-gray-200"
        }`}
      >

        <p
          className={
            darkMode
              ? "text-gray-400"
              : "text-gray-500"
          }
        >
          © 2026 CampusNotes
        </p>

        <div className="flex justify-center gap-8 mt-4 text-sm">

          <span className="cursor-pointer hover:opacity-70">
            About
          </span>

          <span className="cursor-pointer hover:opacity-70">
            Features
          </span>

          <span className="cursor-pointer hover:opacity-70">
            Contact
          </span>

        </div>

      </footer>

    </div>
  );
}

/* STEP COMPONENT */

function Step({ number, title, darkMode }) {
  return (
    <motion.div
      whileHover={{ scale: 1.05 }}
      className={`p-10 rounded-2xl border ${
        darkMode
          ? "bg-[#0f172a] border-cyan-500"
          : "bg-gray-100 border-blue-700"
      }`}
    >
      <div className="text-4xl font-bold mb-4 text-blue-500">
        {number}
      </div>

      <h3 className="text-xl font-semibold">{title}</h3>
    </motion.div>
  );
}