import { useState, useContext, useEffect } from "react";
import { AuthContext } from "../context/AuthContext";
import api from "../api/axios";
import { useNavigate, Link } from "react-router-dom";
import { Eye, EyeOff, Mail, Lock, Sun, Moon } from "lucide-react";
import { motion } from "framer-motion";
import toast, { Toaster } from "react-hot-toast";

export default function Login() {
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  // Default Light Mode
  const [darkMode, setDarkMode] = useState(false);

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState("");

  /* Rotating text */
  const texts = [
    "Smart Academic Notes Sharing",
    "Track Syllabus Progress",
    "Prepare Faster for Exams",
    "Analyze Learning Insights",
  ];

  const [textIndex, setTextIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const savedEmail = localStorage.getItem("rememberEmail");
    if (savedEmail) {
      setEmail(savedEmail);
      setRememberMe(true);
    }
  }, []);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");

    try {
      const res = await api.post("/auth/login", { email, password });

      login(res.data.token, res.data.role, res.data.name || "User");

      rememberMe
        ? localStorage.setItem("rememberEmail", email)
        : localStorage.removeItem("rememberEmail");

      toast.success("Login successful");

      if (res.data.role === "admin") navigate("/admin/dashboard");
      else if (res.data.role === "faculty") navigate("/faculty/dashboard");
      else navigate("/student/dashboard");

    } catch {
      const msg = "Invalid email or password";
      setError(msg);
      toast.error(msg);
    }
  };

  return (
    <div
      className={`min-h-screen flex transition-all duration-500 ${
        darkMode ? "bg-[#020617]" : "bg-white"
      }`}
    >
      <Toaster position="top-right" />

      {/* LEFT HERO SECTION */}
      <div className="hidden md:flex w-[60%] relative items-center justify-center overflow-hidden">

        {/* Gradient */}
        <div
          className={`absolute inset-0 ${
            darkMode
              ? "bg-gradient-to-br from-cyan-900 via-indigo-900 to-black"
              : "bg-gradient-to-br from-blue-100 via-white to-blue-200"
          }`}
        />

        {/* Animated blobs */}
        <motion.div
          animate={{ x: [0, 80, -80, 0], y: [0, -60, 60, 0] }}
          transition={{ duration: 20, repeat: Infinity }}
          className="absolute w-[400px] h-[400px] bg-blue-400/20 rounded-full blur-[120px]"
        />

        <motion.div
          animate={{ x: [0, -120, 120, 0], y: [0, 80, -80, 0] }}
          transition={{ duration: 25, repeat: Infinity }}
          className="absolute w-[500px] h-[500px] bg-indigo-500/20 rounded-full blur-[140px]"
        />

        {/* CONTENT */}
        <div className="relative max-w-xl px-16">

          <h1
            className={`text-6xl font-extrabold mb-6 ${
              darkMode ? "text-white" : "text-[#0a192f]"
            }`}
          >
            CampusNotes
          </h1>

          {/* Animated text */}
          <motion.h2
            key={texts[textIndex]}
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className={`text-2xl font-semibold mb-6 ${
              darkMode ? "text-cyan-400" : "text-blue-700"
            }`}
          >
            {texts[textIndex]}
          </motion.h2>

          <p
            className={`text-lg mb-8 ${
              darkMode ? "text-gray-300" : "text-gray-600"
            }`}
          >
            A centralized platform where students and faculty share organized
            academic notes, track syllabus progress, and prepare smarter for exams.
          </p>

          {/* Features */}
          <div className="space-y-4">

            <Feature text="Smart Notes Sharing" />
            <Feature text="Syllabus Tracking" />
            <Feature text="Exam Mode Preparation" />
            <Feature text="Advanced Analytics" />
            <Feature text="Role Based Dashboards" />

          </div>
        </div>
      </div>

      {/* RIGHT LOGIN SECTION */}
      <motion.div
        initial={{ x: 80, opacity: 0 }}
        animate={{ x: 0, opacity: 1 }}
        transition={{ duration: 0.8 }}
        className={`w-full md:w-[40%] flex items-center justify-center ${
          darkMode ? "bg-[#020617] text-white" : "bg-gray-50"
        }`}
      >

        <div
          className={`w-full max-w-md rounded-2xl shadow-xl px-10 py-12 border backdrop-blur-xl ${
            darkMode
              ? "bg-[#0f172a]/80 border-gray-700"
              : "bg-white border-gray-200"
          }`}
        >

          {/* Dark mode toggle */}
          <div className="flex justify-end mb-4">
            <button
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 border rounded-lg"
            >
              {darkMode ? <Sun size={18} /> : <Moon size={18} />}
            </button>
          </div>

          {/* Center Logo */}
          <div className="flex justify-center mb-6">
            <img src="/college-logo.png" alt="logo" className="w-20 h-20" />
          </div>

          <h1
            className={`text-3xl font-bold text-center ${
              darkMode ? "text-white" : "text-[#0a192f]"
            }`}
          >
            Welcome Back
          </h1>

          <p className="text-gray-500 text-center mt-2 mb-8">
            Login to your dashboard
          </p>

          {error && (
            <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 font-semibold rounded">
              {error}
            </div>
          )}

          <form onSubmit={handleLogin} className="space-y-6">

            {/* EMAIL */}
            <div>
              <label className="text-xs font-bold uppercase mb-2 block">
                Email
              </label>

              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />

                <input
                  type="email"
                  className="w-full pl-12 py-4 bg-gray-50 border-2 rounded-xl focus:border-blue-500 outline-none text-black"
                  placeholder="name@college.edu"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                />
              </div>
            </div>

            {/* PASSWORD */}
            <div>
              <label className="text-xs font-bold uppercase mb-2 block">
                Password
              </label>

              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />

                <input
                  type={showPassword ? "text" : "password"}
                  className="w-full pl-12 pr-12 py-4 bg-gray-50 border-2 rounded-xl focus:border-blue-500 outline-none text-black"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                />

                <button
                  type="button"
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400"
                  onClick={() => setShowPassword(!showPassword)}
                >
                  {showPassword ? <EyeOff /> : <Eye />}
                </button>
              </div>
            </div>

            {/* OPTIONS */}
            <div className="flex justify-between items-center">
              <label className="flex items-center text-sm text-gray-600">
                <input
                  type="checkbox"
                  className="mr-2"
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.target.checked)}
                />
                Remember me
              </label>

              <span className="text-sm text-blue-600 cursor-pointer hover:underline">
                Forgot password?
              </span>
            </div>

            {/* BUTTON */}
            <motion.button
              whileHover={{ scale: 1.03 }}
              whileTap={{ scale: 0.97 }}
              className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-blue-700 transition"
            >
              Sign In
            </motion.button>

          </form>

          <button
            onClick={() => navigate("/")}
            className="mt-6 text-sm opacity-70 hover:opacity-100 block mx-auto"
          >
            ← Back to Home
          </button>

          <p className="mt-8 text-center text-sm text-gray-400 font-semibold">
            Don&apos;t have an account?{" "}
            <Link to="/" className="text-blue-600">
              Contact Admin
            </Link>
          </p>

        </div>
      </motion.div>
    </div>
  );
}

/* Feature Component */
function Feature({ text }) {
  return (
    <motion.div whileHover={{ x: 6 }} className="flex items-center gap-3 text-lg">
      <div className="w-3 h-3 rounded-full bg-blue-500" />
      <span className="text-gray-700 dark:text-gray-300">{text}</span>
    </motion.div>
  );
}